package org.eclipse.rdf4j.query.algebra.evaluation.impl;

import static org.assertj.core.api.Assertions.assertThat;

import java.util.List;
import java.util.stream.Collectors;

import org.eclipse.rdf4j.common.transaction.QueryEvaluationMode;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.QueryLanguage;
import org.eclipse.rdf4j.query.QueryResults;
import org.eclipse.rdf4j.query.impl.EmptyBindingSet;
import org.eclipse.rdf4j.query.parser.ParsedQuery;
import org.eclipse.rdf4j.query.parser.QueryParserUtil;
import org.junit.jupiter.api.Test;

/**
 * ORDER BY must compare values under the configured {@link QueryEvaluationMode}, consistent with how MIN/MAX aggregates
 * and the LMDB native engine thread the mode into their
 * {@link org.eclipse.rdf4j.query.algebra.evaluation.util.ValueComparator}. Cross-type temporal values expose the
 * difference: extended (STANDARD) comparison orders xsd:date against xsd:dateTime on the timeline, while strict
 * comparison has no order for the pair and falls back to the datatype-precedence tie-breaker.
 */
public class OrderByQueryEvaluationModeTest {

	private static final String QUERY = "PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>\n"
			+ "SELECT ?d WHERE { VALUES ?d { \"2022-06-15\"^^xsd:date \"2022-01-01T00:00:00Z\"^^xsd:dateTime } }\n"
			+ "ORDER BY ?d";

	@Test
	public void standardModeSortsCrossTypeTemporalsOnTimeline() {
		assertThat(evaluate(QueryEvaluationMode.STANDARD))
				.containsExactly("2022-01-01T00:00:00Z", "2022-06-15");
	}

	@Test
	public void strictModeSortsCrossTypeTemporalsByDatatypePrecedence() {
		assertThat(evaluate(QueryEvaluationMode.STRICT))
				.containsExactly("2022-06-15", "2022-01-01T00:00:00Z");
	}

	private List<String> evaluate(QueryEvaluationMode mode) {
		DefaultEvaluationStrategy strategy = new DefaultEvaluationStrategy(new EmptyTripleSource(), null);
		strategy.setQueryEvaluationMode(mode);
		ParsedQuery parsed = QueryParserUtil.parseQuery(QueryLanguage.SPARQL, QUERY, null);
		List<BindingSet> rows = QueryResults
				.asList(strategy.precompile(parsed.getTupleExpr()).evaluate(EmptyBindingSet.getInstance()));
		return rows.stream().map(bs -> bs.getValue("d").stringValue()).collect(Collectors.toList());
	}
}
